def assemble_context(retrieved_docs, query):
    context = []
    for i, doc in enumerate(retrieved_docs):
        context.append({
            'content': doc,
            'source_id': f'doc_{i}',
            'score': 0.95,  # from retrieval scores
            'metadata': {'page': i+1, 'section': 'relevant'}
        })
    return {'query': query, 'context': context, 'instructions': 'Use only provided context'}

def generate_with_citations(context, query):
    prompt = f"""Answer using ONLY this context:
{context}

Query: {query}

Use format: Answer [1][2] for citations."""
    response = synthesizer.generate_reply(messages=[{"role": "user", "content": prompt}])
    return response

