from vex.verifications import ContextRelevance

@vex_client.hook("context_relevance")
def verify_retrieval(query, retrieved_docs):
    results = []
    for doc in retrieved_docs:
        score = ContextRelevance().score(query, doc['content'])
        results.append({'doc_id': doc['source_id'], 'relevance_score': score})

    # Block if average relevance < 0.7
    avg_score = np.mean([r['relevance_score'] for r in results])
    if avg_score < 0.7:
        raise ValueError("Low context relevance detected")
    return results

@vex_client.hook(["source_faithfulness", "citation_accuracy"])
def verify_final_output(response, context):
    faithfulness_score = 0.92  # Vex computes
    citation_score = 0.88      # Vex computes

    if faithfulness_score < 0.85:
        return {'status': 'fail', 'reason': 'Hallucination detected'}
    if citation_score < 0.90:
        return {'status': 'fail', 'reason': 'Citation mismatch'}

    return {'status': 'pass', 'scores': {'faithfulness': faithfulness_score, 'citations': citation_score}}
